#!/usr/bin/env python3
"""
bootstrap_g4_validation_gate.py
G4 Validation Gate: Boronic Acid + NU-1000 CH-pi + Formal Gate Report

Writes 3 test files to tests/ in MABE repo.
Total: ~67 new tests across 3 modules.

Data sources:
  Boronic acid: Springsteen & Wang 2002 (Tetrahedron 58:5291)
  NU-1000 MOF: Yabushita et al. 2016 (Chem. Commun. 52:7094)
  Gate report: compiles Davis, CD, boronic acid, NU-1000 results
"""
import base64, os, sys

REPO_ROOT = os.path.dirname(os.path.abspath(__file__))

markers = [
    os.path.join("core", "universal_schema.py"),
    os.path.join("glycan", "parameters_v23.py"),
]
found = sum(1 for m in markers if os.path.exists(os.path.join(REPO_ROOT, m)))
if found == 0:
    parent = os.path.dirname(REPO_ROOT)
    if sum(1 for m in markers if os.path.exists(os.path.join(parent, m))) > 0:
        REPO_ROOT = parent
    else:
        print("WARNING: Could not find MABE repo markers.")

os.makedirs(os.path.join(REPO_ROOT, "tests"), exist_ok=True)

FILES = {
    os.path.join("tests", "test_glycan_g4_boronic_acid.py"): "",
    os.path.join("tests", "test_glycan_g4_nu1000_chpi.py"): "",
    os.path.join("tests", "test_glycan_g4_gate_report.py"): "",
}

for rel_path, b64_content in FILES.items():
    full_path = os.path.join(REPO_ROOT, rel_path)
    content = base64.b64decode(b64_content)
    with open(full_path, "wb") as f:
        f.write(content)
    print(f"  wrote {rel_path} ({len(content)} bytes)")

print()
print("G4 validation gate tests installed in MABE.")
print("Run: python -m pytest tests/test_glycan_g4_boronic_acid.py tests/test_glycan_g4_nu1000_chpi.py tests/test_glycan_g4_gate_report.py -v -s")